-- ============================================================
-- DDL: Create table PedidosPendientes
-- ============================================================
IF OBJECT_ID('dbo.PedidosPendientes', 'U') IS NOT NULL
    DROP TABLE dbo.PedidosPendientes;
GO

CREATE TABLE dbo.PedidosPendientes (
    Id_Vencimiento    INT             NOT NULL,
    No_pedido         VARCHAR(35)     NOT NULL,
    Id_pedido         INT             NOT NULL,
    cod_cliente       INT             NOT NULL,
    Cliente           VARCHAR(100)    NOT NULL,
    Nit               VARCHAR(20)     NOT NULL,
    cod_produc        VARCHAR(15)     NOT NULL,
    descripcion       VARCHAR(250)    NOT NULL,
    cantidad          INT             NOT NULL,
    CantidadOriginal  INT             NOT NULL,
    valor             DECIMAL(18,5)   NOT NULL,
    fechaPedido       DATE            NOT NULL,
    fechaVencim       DATE            NOT NULL,
    metalizado        TINYINT         NOT NULL DEFAULT 0,
    Puntoventa        TINYINT         NOT NULL DEFAULT 0,
    CONSTRAINT PK_PedidosPendientes PRIMARY KEY (Id_Vencimiento)
);
GO

